#include <iostream>
#include <iomanip>

int main() {
    int n;
    std::cin >> n;
    int sum = 0;
    for (int i = 0; i < n; i++) {
        int x;
        std::cin >> x;
        sum += x;
    }
    std::cout << std::fixed << std::setprecision(2) << (double)sum / n << std::endl;
    return 0;
}
